const raw = $json.body ?? $json ?? {};

function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return undefined;
}
function asArray(v) {
  if (Array.isArray(v)) return v;
  if (v === undefined || v === null || v === '') return [];
  return [v];
}
function toInt(v, d = 10) {
  const n = parseInt(v, 10);
  return Number.isFinite(n) && n > 0 ? n : d;
}
function normUrl(x) {
  return String(x || '').trim();
}

const platform = String(pickFirst(raw.platform, '') || '').trim().toLowerCase();
const inputMode = String(pickFirst(raw.input_mode, raw.inputMode, '') || '').trim().toLowerCase();
const callbackUrl = pickFirst(raw.callback_url, raw.callbackUrl, raw.webhook_callback);
const apiKey = pickFirst(raw.api_key, raw.apiKey);
const apifyToken = pickFirst(raw.apify_token, raw.apifyToken, 'YOUR_APIFY_TOKEN');
const workflowId = pickFirst(raw.workflow_id, 'flow0010');
const taskId = pickFirst(raw.task_id, raw.taskId, 'social_' + Date.now());

const payload = raw.payload && typeof raw.payload === 'object' ? raw.payload : raw;

let taskCount = 0;
let normalizedPayload = {};
let modeResolved = inputMode;

if (!platform) throw new Error('缺少 platform');
if (!apiKey) throw new Error('缺少 api_key');
if (!callbackUrl) throw new Error('缺少 callback_url');

if (platform === 'tiktok' && inputMode === 'url') {
  const postURLs = asArray(pickFirst(payload.postURLs, payload.urls, payload.url_list, payload.url))
    .map(normUrl).filter(Boolean);
  if (!postURLs.length) throw new Error('TikTok URL模式缺少 postURLs/urls/url');
  normalizedPayload = { postURLs };
  taskCount = postURLs.length;
} else if (platform === 'tiktok' && inputMode === 'keyword') {
  const searchQueries = asArray(pickFirst(payload.searchQueries, payload.keywords, payload.queries, payload.keyword))
    .map(v => String(v || '').trim()).filter(Boolean);
  const limit = toInt(pickFirst(payload.limit, payload.resultsPerPage, payload.count), 10);
  if (!searchQueries.length) throw new Error('TikTok 关键词模式缺少 searchQueries/keywords/keyword');
  normalizedPayload = { searchQueries, limit };
  taskCount = searchQueries.length;
} else if (platform === 'facebook') {
  modeResolved = 'url';
  const urls = asArray(pickFirst(payload.startUrls, payload.start_urls, payload.urls, payload.url))
    .map(item => typeof item === 'string' ? item : (item?.url || ''))
    .map(normUrl).filter(Boolean);
  const startUrls = urls.map(url => ({ url }));
  const resultsLimit = toInt(pickFirst(payload.resultsLimit, payload.results_limit, payload.limit), 20);
  const captionText = Boolean(pickFirst(payload.captionText, payload.caption_text, false));
  if (!startUrls.length) throw new Error('Facebook 模式缺少 startUrls/urls/url');
  normalizedPayload = { startUrls, resultsLimit, captionText };
  taskCount = startUrls.length;
} else if (platform === 'instagram') {
  modeResolved = 'url';
  const directUrls = asArray(pickFirst(payload.directUrls, payload.direct_urls, payload.urls, payload.url))
    .map(item => typeof item === 'string' ? item : (item?.url || ''))
    .map(normUrl).filter(Boolean);
  const resultsLimit = toInt(pickFirst(payload.resultsLimit, payload.results_limit, payload.limit), 10);
  if (!directUrls.length) throw new Error('Instagram 模式缺少 directUrls/urls/url');
  normalizedPayload = { directUrls, resultsLimit };
  taskCount = directUrls.length;
} else {
  throw new Error(`暂不支持的 platform/input_mode 组合: ${platform}/${inputMode}`);
}

return [{
  json: {
    task_id: taskId,
    workflow_id: workflowId,
    api_key: apiKey,
    apify_token: apifyToken,
    callback_url: callbackUrl,
    platform,
    input_mode: modeResolved,
    taskCount,
    payload: normalizedPayload,
    request_meta: {
      source: pickFirst(raw.source, 'web'),
      client_uid: pickFirst(raw.client_uid, raw.user_id, ''),
      batch_name: pickFirst(raw.batch_name, '')
    }
  }
}];

const input = $('标准化输入').first().json;
const { platform, input_mode, payload, apify_token } = input;

let actorPath = '';
let actorInput = {};

if (platform === 'tiktok' && input_mode === 'url') {
  actorPath = 'GdWCkxBtKWOsKjdch';
  actorInput = {
    excludePinnedPosts: true,
    proxyCountryCode: 'None',
    scrapeRelatedVideos: false,
    postURLs: payload.postURLs,
    shouldDownloadAvatars: false,
    shouldDownloadCovers: false,
    shouldDownloadMusicCovers: false,
    shouldDownloadSlideshowImages: false,
    shouldDownloadSubtitles: true,
    shouldDownloadVideos: true
  };
} else if (platform === 'tiktok' && input_mode === 'keyword') {
  actorPath = 'GdWCkxBtKWOsKjdch';
  actorInput = {
    excludePinnedPosts: true,
    proxyCountryCode: 'None',
    resultsPerPage: payload.limit,
    scrapeRelatedVideos: false,
    searchQueries: payload.searchQueries,
    shouldDownloadAvatars: false,
    shouldDownloadCovers: false,
    shouldDownloadMusicCovers: false,
    shouldDownloadSlideshowImages: false,
    shouldDownloadSubtitles: true,
    shouldDownloadVideos: true
  };
} else if (platform === 'facebook') {
  actorPath = 'apify/facebook-posts-scraper';
  actorInput = {
    captionText: payload.captionText,
    resultsLimit: payload.resultsLimit,
    startUrls: payload.startUrls
  };
} else if (platform === 'instagram') {
  actorPath = 'apify/instagram-scraper';
  actorInput = {
    addParentData: false,
    directUrls: payload.directUrls,
    enhanceUserSearchWithFacebookPage: false,
    isUserReelFeedURL: false,
    isUserTaggedFeedURL: false,
    resultsLimit: payload.resultsLimit,
    resultsType: 'posts',
    searchLimit: 1,
    searchType: 'hashtag'
  };
} else {
  throw new Error(`未支持的 actor 路由: ${platform}/${input_mode}`);
}

const encodedActor = encodeURIComponent(actorPath);

return [{
  json: {
    ...input,
    actorPath,
    actorInput,
    run_url: `https://api.apify.com/v2/acts/${encodedActor}/runs?token=${apify_token}`,
    status_base_url: `https://api.apify.com/v2`,
  }
}];

const platform = $('标准化输入').first().json.platform;
const inputMode = $('标准化输入').first().json.input_mode;
const items = $input.all();
const cleaned = [];

for (const item of items) {
  const data = item.json || {};

  if (platform === 'tiktok') {
    let subtitleUrl = '';
    if (data.videoMeta && Array.isArray(data.videoMeta.subtitleLinks)) {
      const sub = data.videoMeta.subtitleLinks.find(s =>
        String(s.language || '').toLowerCase().startsWith('en')
      ) || data.videoMeta.subtitleLinks[0];
      if (sub) subtitleUrl = sub.downloadLink || '';
    }

    cleaned.push({
      json: {
        platform,
        input_mode: inputMode,
        source_key: inputMode === 'keyword' ? (data.input || data.searchQuery || '') : (data.webVideoUrl || data.url || ''),
        post_url: data.webVideoUrl || data.url || '',
        author_name: data.authorMeta ? data.authorMeta.name : '',
        author_profile_url: data.authorMeta ? data.authorMeta.profileUrl : '',
        text: data.text || '',
        play_count: data.playCount || 0,
        like_count: data.diggCount || 0,
        comment_count: data.commentCount || 0,
        share_count: data.shareCount || 0,
        collect_count: data.collectCount || 0,
        fans_count: data.authorMeta ? data.authorMeta.fans : 0,
        author_signature: data.authorMeta ? data.authorMeta.signature : '',
        cover_url: data.videoMeta ? data.videoMeta.originalCoverUrl : '',
        published_at: data.createTimeISO || '',
        video_url: (data.mediaUrls && data.mediaUrls.length > 0) ? data.mediaUrls[0] : '',
        script_text: '',
        _subtitleUrl: subtitleUrl,
        raw: data,
        hasData: true
      }
    });
  } else if (platform === 'facebook') {
    cleaned.push({
      json: {
        platform,
        input_mode: 'url',
        source_key: data.inputUrl || data.pageUrl || data.url || '',
        page_name: data.pageName || data.pageTitle || data.ownerName || '',
        post_id: data.postId || data.id || '',
        post_url: data.postUrl || data.url || '',
        text: data.text || data.caption || data.message || '',
        published_at: data.time || data.timestamp || data.createdAt || '',
        like_count: data.reactionsCount || data.likes || 0,
        comment_count: data.commentsCount || data.comments || 0,
        share_count: data.sharesCount || data.shares || 0,
        image_urls: Array.isArray(data.images) ? data.images : [],
        video_url: data.videoUrl || '',
        author_name: data.authorName || data.ownerName || '',
        author_profile_url: data.authorProfileUrl || data.authorUrl || '',
        raw: data,
        hasData: true
      }
    });
  } else if (platform === 'instagram') {
    const postUrl = data.url || data.postUrl || '';
    if (!postUrl) continue;
    cleaned.push({
      json: {
        platform,
        input_mode: 'url',
        source_key: data.inputUrl || data.ownerUsername || '',
        post_url: postUrl,
        text: data.caption || '',
        published_at: data.timestamp || data.latestComments?.[0]?.timestamp || '',
        like_count: data.likesCount || 0,
        comment_count: data.commentsCount || 0,
        share_count: 0,
        video_url: data.videoUrl || '',
        display_url: data.displayUrl || '',
        image_urls: Array.isArray(data.images) ? data.images : [],
        author_name: data.ownerFullName || data.ownerUsername || '',
        author_username: data.ownerUsername || '',
        author_profile_url: data.inputUrl || data.ownerProfilePicUrl || '',
        shortcode: data.shortCode || data.shortcode || '',
        media_type: data.type || '',
        raw: data,
        hasData: true
      }
    });
  }
}

if (!cleaned.length) {
  return [{ json: { hasData: false, platform, input_mode: inputMode } }];
}

return cleaned;

const items = $input.all();

return items.map(item => {
  let subText = '';
  const rawContent = item.json.data || item.json;

  if (typeof rawContent === 'string' && rawContent.length > 0 && !rawContent.includes('error')) {
    const lines = rawContent.split(/\r?\n/);
    const texts = [];
    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) continue;
      if (/^WEBVTT/i.test(trimmed)) continue;
      if (/^\d+$/.test(trimmed)) continue;
      if (/^\d{2}:\d{2}:\d{2}/.test(trimmed)) continue;
      texts.push(trimmed);
    }
    subText = texts.join('\n');
  }

  const original = item.pairedItem
    ? $items('清洗结果(统一)')[item.pairedItem.item].json
    : {};

  return {
    json: {
      ...original,
      script_text: subText || original.script_text || ''
    }
  };
});
